import{_ as d,c as r,o as a,a1 as e}from"./chunks/framework.DDNAyvCW.js";const o="/assets/aipre.CV7wkTnH.png",A=JSON.parse('{"title":"AI 偏好设置","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/preferences/index.md","filePath":"docs/ai/preferences/index.md"}'),l={name:"docs/ai/preferences/index.md"};function n(s,t,i,h,c,g){return a(),r("div",null,t[0]||(t[0]=[e('<h1 id="ai-偏好设置" tabindex="-1">AI 偏好设置 <a class="header-anchor" href="#ai-偏好设置" aria-label="Permalink to &quot;AI 偏好设置&quot;">​</a></h1><p>微调 AI 助手的行为方式，从推理深度到命令执行策略。</p><p><img src="'+o+'" alt=""></p><h2 id="设置参考" tabindex="-1">设置参考 <a class="header-anchor" href="#设置参考" aria-label="Permalink to &quot;设置参考&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设置项</th><th>默认值</th><th>功能说明</th><th>何时调整</th></tr></thead><tbody><tr><td><strong>扩展思考</strong></td><td>开启</td><td>为 AI 分配一个 token 预算，在回复前进行逐步推理。更高的预算能产生更全面、更准确的回答。</td><td>复杂的多步骤任务时增加预算。简单问题需要更快响应时减少（或关闭）预算。</td></tr><tr><td><strong>自动执行只读命令</strong></td><td>关闭</td><td>所有会话中的只读命令（如 ls、cat、grep）将自动执行，无需确认。</td><td>仅在熟悉 AI 的行为后再启用。</td></tr><tr><td><strong>自动执行</strong></td><td>关闭</td><td>启用后，Agent 模式会自动执行命令，无需等待您的批准。</td><td>仅在熟悉 AI 的行为并已配置安全规则阻止危险命令后再启用。</td></tr><tr><td><strong>安全配置</strong></td><td>--</td><td>定义策略，防止 AI 执行危险或破坏性命令（例如 <code>rm -rf /</code>、<code>DROP DATABASE</code>）。</td><td>在启用自动执行前进行配置。每当环境或风险容忍度发生变化时进行审查和更新。</td></tr><tr><td><strong>OpenAI 推理级别</strong></td><td>低</td><td>控制 OpenAI 模型的推理强度：<strong>低</strong>（快速，成本低）、<strong>中</strong>（均衡）、<strong>高</strong>（深度推理，准确性最高）。</td><td>复杂故障排查或规划任务时提升至中或高。日常操作保持低级别以节省成本和延迟。</td></tr><tr><td><strong>代理配置</strong></td><td>关闭</td><td>通过 HTTP/SOCKS 代理路由 AI API 流量。可配置协议、主机名、端口和可选的身份认证。</td><td>当您的网络需要代理才能访问外部 API 端点时启用。使用 Ollama 等本地模型时不需要。</td></tr><tr><td><strong>Shell 集成超时</strong></td><td>4 秒</td><td>执行命令时终端等待 Shell 集成初始化的最大时间。</td><td>在慢速连接或负载较重的主机上出现超时错误时增加。在无响应的主机上希望更快失败时减少。</td></tr></tbody></table><hr><h2 id="扩展思考" tabindex="-1">扩展思考 <a class="header-anchor" href="#扩展思考" aria-label="Permalink to &quot;扩展思考&quot;">​</a></h2><p>扩展思考为 AI 提供了一个专门的推理阶段，在生成回复之前进行思考。您可以控制分配给该阶段的 token 预算。</p><ul><li><strong>更高预算</strong> = 更全面的推理，复杂任务的准确性更好，但响应更慢。</li><li><strong>更低预算</strong> = 更快的响应，对于简单问题已经足够。</li></ul><p>在偏好设置面板中调整预算滑块，找到适合您工作流的平衡点。</p><hr><h2 id="自动执行" tabindex="-1">自动执行 <a class="header-anchor" href="#自动执行" aria-label="Permalink to &quot;自动执行&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">安全影响</p><p>启用自动执行后，AI 将<strong>无需您的确认</strong>即可运行命令。这对自动化来说功能强大，但也带有风险。错误的提示或意外的 AI 行为可能会执行破坏性命令。</p><p><strong>启用自动执行前：</strong></p><ol><li>配置<strong>安全规则</strong>以阻止危险命令。</li><li>在手动模式下用您的常用提示测试 AI 的行为。</li><li>先在非生产环境中使用。</li></ol></div><p>关闭时（默认状态），AI 生成的每条命令都需要您明确批准后才会执行。</p><hr><h2 id="安全配置" tabindex="-1">安全配置 <a class="header-anchor" href="#安全配置" aria-label="Permalink to &quot;安全配置&quot;">​</a></h2><p>安全配置允许您定义命令或模式的黑名单，无论自动执行设置如何，AI 都不允许执行这些命令。</p><ul><li>为危险操作添加模式（例如 <code>rm -rf</code>、<code>mkfs</code>、<code>shutdown</code>、<code>DROP TABLE</code>）。</li><li>规则同时适用于 Command 模式和 Agent 模式。</li><li>随着环境的变化，定期审查您的安全规则。</li></ul><hr><h2 id="openai-推理级别" tabindex="-1">OpenAI 推理级别 <a class="header-anchor" href="#openai-推理级别" aria-label="Permalink to &quot;OpenAI 推理级别&quot;">​</a></h2><p>此设置仅影响 OpenAI 兼容的模型。它控制模型投入多少推理能力：</p><table tabindex="0"><thead><tr><th>级别</th><th>响应速度</th><th>准确性</th><th>成本</th></tr></thead><tbody><tr><td><strong>低</strong></td><td>最快</td><td>适合日常任务</td><td>最低</td></tr><tr><td><strong>中</strong></td><td>适中</td><td>适合较复杂的问题</td><td>适中</td></tr><tr><td><strong>高</strong></td><td>最慢</td><td>适合复杂推理任务</td><td>最高</td></tr></tbody></table><hr><h2 id="代理配置" tabindex="-1">代理配置 <a class="header-anchor" href="#代理配置" aria-label="Permalink to &quot;代理配置&quot;">​</a></h2><p>如果您的网络需要代理才能访问外部 AI API，请在此处配置。代理默认为关闭状态。</p><ul><li><strong>协议</strong> -- HTTP、HTTPS 或 SOCKS5</li><li><strong>主机名</strong> -- 代理服务器地址</li><li><strong>端口</strong> -- 代理服务器端口</li><li><strong>用户名 / 密码</strong> -- 可选的身份认证凭证</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>代理设置全局应用于所有 AI API 流量。如果您通过 Ollama 使用本地模型，发往 <code>localhost</code> 的流量会绕过代理。</p></div><hr><h2 id="shell-集成超时" tabindex="-1">Shell 集成超时 <a class="header-anchor" href="#shell-集成超时" aria-label="Permalink to &quot;Shell 集成超时&quot;">​</a></h2><p>Shell 集成超时控制 Chaterm 在执行命令时等待终端 Shell 初始化集成钩子的最长时间。如果超时，命令执行将被中止以防止阻塞。</p><p>默认的 <strong>4 秒</strong>适用于大多数连接。对于高延迟或负载较重的远程主机，请适当增加。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/docs/ai/dialogs/">AI 对话</a> -- 了解 Command 和 Agent 模式</li><li><a href="/docs/ai/settings/">AI 设置</a> -- 配置提供商、模型和创建新对话</li></ul>',34)]))}const u=d(l,[["render",n]]);export{A as __pageData,u as default};
